package com.wjx871.population.certificate;import com.wjx871.population.audit.OperationLogService;import com.wjx871.population.common.BusinessException;import com.wjx871.population.reference.DataDictionaryService;import com.wjx871.population.security.*;import jakarta.servlet.http.HttpServletRequest;import java.time.*;import java.util.*;import lombok.RequiredArgsConstructor;import org.springframework.data.domain.*;import org.springframework.http.HttpStatus;import org.springframework.stereotype.Service;import org.springframework.transaction.annotation.Transactional;
@Service@RequiredArgsConstructor public class CertificateService {private final CertificateMapper mapper;private final DataDictionaryService dictionaries;private final SensitiveDataMaskingService masking;private final OperationLogService audit;
public Page<CertificateView> search(Long personId,String personName,String type,String no,String status,LocalDate issueFrom,LocalDate issueTo,LocalDate expireFrom,LocalDate expireTo,Integer days,Pageable p){if(days!=null){if(days<0)throw bad("expiringWithinDays 不能小于0");expireFrom=LocalDate.now();expireTo=LocalDate.now().plusDays(days);}if("EXPIRED".equals(norm(status))){LocalDate yesterday=LocalDate.now().minusDays(1);if(expireTo==null||expireTo.isAfter(yesterday))expireTo=yesterday;}DataScopeCriteria s=DataScopeCriteria.current();List<CertificateView> rows=mapper.search(personId,trim(personName),norm(type),trim(no),dbStatus(status),issueFrom,issueTo,expireFrom,expireTo,s,p.getPageSize(),p.getOffset()).stream().map(x->CertificateView.from(x,masking)).toList();return new PageImpl<>(rows,p,mapper.count(personId,trim(personName),norm(type),trim(no),dbStatus(status),issueFrom,issueTo,expireFrom,expireTo,s));}
public CertificateView get(Long id){return CertificateView.from(mapper.findScopedById(id,DataScopeCriteria.current()).orElseThrow(()->notFound()),masking);}public Page<CertificateView> byPerson(Long id,Pageable p){return search(id,null,null,null,null,null,null,null,null,null,p);}
@Transactional public CertificateView create(CertificateCreateRequest q,HttpServletRequest h){String person=mapper.personStatus(q.personId()).orElseThrow(()->new BusinessException(HttpStatus.NOT_FOUND,"人员不存在"));if("CANCELLED".equals(person)||"DECEASED".equals(person))throw conflict("已注销或死亡人员不能新增有效证件");validate(q.certificateType(),q.issueDate(),q.expireDate());Certificate v=new Certificate();v.setPersonId(q.personId());v.setCertificateType(norm(q.certificateType()));v.setCertificateNo(q.certificateNo().trim());v.setIssueDate(q.issueDate());v.setExpireDate(q.expireDate());v.setStatus("ACTIVE");v.setVersion(0);mapper.insert(v);log("CERTIFICATE_CREATE",v.getCertificateId(),h);return get(v.getCertificateId());}
@Transactional public CertificateView update(Long id,CertificateUpdateRequest q,HttpServletRequest h){Certificate v=requireWritable(id);validate(q.certificateType(),q.issueDate(),q.expireDate());v.setCertificateType(norm(q.certificateType()));v.setCertificateNo(q.certificateNo().trim());v.setIssueDate(q.issueDate());v.setExpireDate(q.expireDate());if(mapper.update(v,q.version())==0)throw conflict("证件已被其他操作修改");log("CERTIFICATE_UPDATE",id,h);return get(id);}
@Transactional public void cancel(Long id,CertificateCancelRequest q,HttpServletRequest h){requireWritable(id);if(mapper.cancel(id,q.reason(),q.version())==0)throw conflict("证件状态或版本已变化");log("CERTIFICATE_CANCEL",id,h);}
private Certificate requireWritable(Long id){Certificate scoped=mapper.findScopedById(id,DataScopeCriteria.current()).orElseThrow(()->notFound());if(!"ACTIVE".equals(scoped.getStatus()))throw conflict("已注销证件不能修改或重复注销");return scoped;}private void validate(String type,LocalDate issue,LocalDate expire){String t=norm(type);if("RESIDENCE_PERMIT".equals(t))throw bad("居住证必须通过专业居住证模块管理");if(!dictionaries.enabled("CERTIFICATE_TYPE",t))throw bad("证件类型不存在或已停用");if(issue.isAfter(LocalDate.now()))throw bad("签发日期不能晚于当前日期");if(expire!=null&&expire.isBefore(issue))throw bad("有效期截止日期不能早于签发日期");}private String dbStatus(String s){s=norm(s);return "EXPIRED".equals(s)?"ACTIVE":s;}private String norm(String x){x=trim(x);return x==null?null:x.toUpperCase(Locale.ROOT);}private String trim(String x){return x==null||x.isBlank()?null:x.trim();}private void log(String op,Long id,HttpServletRequest h){audit.recordTransactional(CurrentUserContext.requireUser().userId(),op,"CERTIFICATE",String.valueOf(id),h);}private BusinessException bad(String m){return new BusinessException(HttpStatus.BAD_REQUEST,m);}private BusinessException conflict(String m){return new BusinessException(HttpStatus.CONFLICT,m);}private BusinessException notFound(){return new BusinessException(HttpStatus.NOT_FOUND,"证件不存在");}}
